const PROCESSING_FEE = 5;

const PREMIUM_BY_TYPE: Record<string, number> = {
  amulet: 71,
  staff: 93,
  potion: 49,
};

export function runScenario(input: unknown): unknown {
  const { steps } = input as Input;
  const items = steps[0].items;
  const premium = computePremium(items);
  return { results: [{ premium }] };
}

function computePremium(items: Array<{ type: string }>): number {
  if (items.length === 0) return PROCESSING_FEE;
  return PREMIUM_BY_TYPE[items[0].type];
}
